    resetPlayer(playerNum) {
      const player = playerNum === 1 ? this.player1 : this.player2;
      player.distance = 0;
      player.speed = 0;
      player.lastRandom = null;
      player.maxSpeed = 0;
      player.progress = 0;
      player.timeLeft = 30;
      player.timeUsed = 0;
      player.active = false;
