              window.sessionStorage.setItem('firstPlacenmu', player.distance)
              window.sessionStorage.setItem('firstPlaceimg', this.youxiimg2)
            } else if (player.distance > this.secondPlacenmu && player.distance < this.firstPlacenmu) {
              window.sessionStorage.setItem('secondPlacenmu', player.distance)
              window.sessionStorage.setItem('secondPlaceimg', this.youxiimg2)
            }
            this.player2.timer = null;
            setTimeout(() => {
              this.player2 = {
                id: 1,
                distance: 0,      // 背景滚动距离（像素）
                speed: 0,         // 当前速度（像素/秒）
                lastRandom: 0,
                maxSpeed: 0,
                progress: 0,      // 进度条百分比
                timeLeft: 30,
                timeUsed: 0,
                active: false,
                timer: null
              }
              if(this.player1.timeLeft == '30'){
                
                this.$store.commit('SET_YUNDONGTYPE', '')
               this.$router.push({ path: '/'});
              }
              // this.resetGame()
            }, 5000);
          }
          // console.log(player, '玩家已结束')
          // 检查是否两个玩家都结束了
          this.checkGameFinished();
        }
      }, 1000);
    },

    togglePlayer(playerNum) {
      const player = playerNum === 1 ? this.player1 : this.player2;

      if (player.timeLeft <= 0) {
        // 时间已经用完，不能切换状态
        return;
      }

      if (player.active) {
        // 暂停玩家
        player.active = false;
        if (player.timer) {
          clearInterval(player.timer);
          player.timer = null;
        }
      } else {
        console.log('开始玩家')
        this.gameStarted = true;
        this.gameFinished = false;

        // 继续玩家
        this.resetPlayer(playerNum);
        this.startPlayer(playerNum);
        this.animateBackground();
      }
    },

    animateBackground() {
      const animate = () => {
        // 计算每帧的滚动距离
        // 假设60fps，每帧时间约为16.67ms
        const frameTime = 16.67;
        //console.log(this.player1)
        // 更新玩家1的背景（从上到下移动）
        if (this.player1.active && this.player1.timeLeft > 0) {
          const pixelsPerFrame1 = (this.player1.speed * frameTime) / 1000;
          this.player1.distance += pixelsPerFrame1;
          this.player1.progress = Math.min(100, (this.player1.distance / this.maxDistance) * 100);
        }

        // 更新玩家2的背景（从上到下移动）
        if (this.player2.active && this.player2.timeLeft > 0) {
          const pixelsPerFrame2 = (this.player2.speed * frameTime) / 1000;
          this.player2.distance += pixelsPerFrame2;
          this.player2.progress = Math.min(100, (this.player2.distance / this.maxDistance) * 100);
        }

        // 继续下一帧动画
        if (this.gameStarted && !this.gameFinished) {
          this.animationFrame = requestAnimationFrame(animate);
        }
      };

      // 开始动画循环
      this.animationFrame = requestAnimationFrame(animate);
    },

    checkGameFinished() {
      // 两个玩家都结束了才结束游戏
      if ((this.player1.timeLeft <= 0 || !this.player1.active) &&
        (this.player2.timeLeft <= 0 || !this.player2.active)) {
        this.endGame();
      }
    },
    endGame() {
      this.$store.commit('SET_ID', '1')
      this.gameFinished = true;

      // 最终进度条更新
      this.player1.progress = Math.min(100, (this.player1.distance / this.maxDistance) * 100);
      this.player2.progress = Math.min(100, (this.player2.distance / this.maxDistance) * 100);

      // 停止动画
      cancelAnimationFrame(this.animationFrame);
    },

    resetGame() {
      this.gameStarted = false;
      this.gameFinished = false;

      // 停止所有计时器
      if (this.player1.timer) {
        clearInterval(this.player1.timer);
        this.player1.timer = null;
      }
      if (this.player2.timer) {
        clearInterval(this.player2.timer);
        this.player2.timer = null;
      }

      // 停止动画
      cancelAnimationFrame(this.animationFrame);

      // 重置玩家数据
      this.resetPlayer(1);
      this.resetPlayer(2);
    }
  },
}
</script>

