<template>
  <div id="appShow2" class="game-container">
    <div class="game-background2">
      <img src="../assets/image/beijing2.png" alt="游戏背景" class="background-image">
    </div>
    <header>
      <h1><i class="fas fa-robot"></i> 123木头人游戏</h1>
      <p>当木头人转身时前进，当木头人回头时停止！</p>
    </header>
    <div class="game-area">
      <div class="instructions-toggle">
        <!-- <div class="instructions-title">
          <div><i class="fas fa-info-circle"></i> 游戏规则 (点击展开/收起)</div>
          <div><i class="fas" :class="showInstructions ? 'fa-chevron-up' : 'fa-chevron-down'"></i></div>
        </div> -->
        <div class="instructions-content" v-if="showInstructions">
          <div class="instruction"><i class="fas fa-check-circle" style="color: #06d6a0;"></i> 木头人背对时（绿色），玩家可以移动</div>
          <div class="instruction"><i class="fas fa-times-circle" style="color: #ef476f;"></i> 木头人面对时（红色），玩家不能移动，移动会被淘汰
          </div>
          <div class="instruction"><i class="fas fa-flag-checkered" style="color: #ffd166;"></i> 到达终点线（右侧）的玩家获胜</div>
          <!--   <div class="instruction"><i class="fas fa-users"></i> 8个玩家，使用数字键1-8控制相应玩家移动</div> -->
        </div>
      </div>

      <div class="game-main">
        <div class="right-panel">
          <!-- <div class="paodaobeijingtu">
             <img src="../assets/image/paodao.png" style="display: block;width: 100%;height: 100%;" alt="">
          </div> -->
          <div class="game-field-container">
            <div class="game-field">
              <div class="start-line"></div>
              <div class="finish-line"></div>
              <!--  <div class="start-label">起点</div>
                            <div class="finish-label">终点</div> -->

              <!-- 玩家在游戏区域中的标记 -->
              <div v-for="player in players" :key="'token-' + player.id" class="player-token" :style="{
                left: 'calc(40px + ' + (player.position * 0.9) + '%)',
                top: player.fieldPosition + 'px',
                backgroundColor: player.color,
                color: player.textColor,
                transform: player.isWinner ? 'scale(1.2)' : 'scale(1)'
              }">
                {{ player.id }}
                <div v-if="player.isWinner"
                  style="position: absolute; top: -22px; left: 50%; transform: translateX(-50%); font-size: 1.3rem;">
                  <i class="fas fa-crown" style="color: #ffd166;"></i>
                </div>
              </div>
            </div>
          </div>
        </div>
      </div>

      <!-- 键盘控制提示 -->
      <div class="key-hints">
        <div class="players-container">
          <div v-for="player in players" :key="player.id" class="player-card" :class="{
            active: player.isMoving && !player.eliminated && !player.isWinner,
            eliminated: player.eliminated,
            winner: player.isWinner
          }">
            <div class="player-icon" :style="{ color: player.color }">
              <img :src="player.icon" style="display: block;width: 100%;height: 100%;" alt="">
            </div>
            <div class="player-name">玩家 {{ player.id }}</div>
            <div class="player-status" :class="player.statusClass">
              {{ player.statusText }}
            </div>
            <div class="player-progress-container">
              <div class="player-progress">
                <div class="player-progress-bar" :style="{ width: player.position + '%' }"></div>
              </div>
              <div class="player-progress-text">
                <span>进度</span>
                <span>{{ Math.min(100, Math.floor(player.position)) }}%</span>
              </div>
            </div>
          </div>
        </div>
        <!-- <div class="key-hint" v-for="player in players" :key="'key-hint-' + player.id">
                    <span>玩家{{ player.id }}:</span>
                    <span class="key">{{ player.key }}</span>
                </div> -->
      </div>
      <!-- <div class="really">
        <div v-for="player in players" :key="player.id" class="really-container">
          <div class="hole-border" v-show="player.really">
            <img src="../assets/image/really.png" class="reallyImg" alt="">
          </div>
        </div>
      </div> -->
      <div class="controls-container">
        <div class="game-info">
          <div class="info-item">
            <div class="info-value">{{ activePlayersCount }}</div>
            <div class="info-label">游戏中</div>
          </div>
          <div class="info-item">
            <div class="info-value">{{ winnersCount }}</div>
            <div class="info-label">已获胜</div>
          </div>
          <div class="info-item">
            <div class="info-value">{{ eliminatedCount }}</div>
            <div class="info-label">被淘汰</div>
          </div>
          <div class="info-item">
            <div class="info-value">{{ roundCount }}</div>
            <div class="info-label">回合数</div>
          </div>
        </div>

        <!-- <div class="controls">
          <button class="btn btn-start" @click="startGame" :disabled="gameRunning">
            <i class="fas fa-play"></i> {{ gameRunning ? '游戏进行中' : '开始游戏' }}
          </button>
          <button class="btn btn-reset" @click="resetGame">
            <i class="fas fa-redo"></i> 重置游戏
          </button>
        </div> -->
      </div>
    </div>
    <!-- 游戏结果弹窗 -->
    <div class="game-message" v-if="showGameResult">
      <div class="message-content">
        <h2>{{ gameResultTitle }}</h2>
        <p>{{ gameResultMessage }}</p>
        <div style="display: flex; gap: 15px; justify-content: center; margin-top: 25px;">
          <!-- <button class="btn btn-reset" @click="resetGame">
            <i class="fas fa-redo"></i> 重新开始
          </button>
          <button class="btn btn-start" @click="closeResult">
            <i class="fas fa-times"></i> 关闭
          </button> -->
        </div>
      </div>
    </div>
    <div class="left-panel">
      <div class="wooden-man-container">
        <div class="wooden-man" :class="woodenManClass">
          <i class="fas fa-robot"></i>
        </div>
        <div class="status-text">
          {{ woodenManFacing ? '木头人正在看着你！' : '木头人转身了，快前进！' }}
        </div>
        <div class="timer">
          状态剩余时间: {{ countdown }}秒
        </div>
      </div>
    </div>
    <div @click="daji1">
         <audio ref="mutourenPlayers" :src="mutourenyinyue" loop></audio>
    </div>
    
  </div>
</template>

<script>
export default {
  data() {
    return {
      gameRunning: false,
      woodenManFacing: false, // true: 面对玩家, false: 背对玩家
      countdown: 0,
      roundCount: 0,
      players: [
        { id: 1, position: 0, isMoving: false, eliminated: false, isWinner: false, fieldPosition: 16, key: '1', color: '#ef476f', textColor: '#fff', icon: require('../assets/image/wanjia.png'), really: true },
        { id: 2, position: 0, isMoving: false, eliminated: false, isWinner: false, fieldPosition: 76, key: '2', color: '#06d6a0', textColor: '#1a1a2e', icon: require('../assets/image/wanjia.png'), really: true },
        { id: 3, position: 0, isMoving: false, eliminated: false, isWinner: false, fieldPosition: 136, key: '3', color: '#118ab2', textColor: '#fff', icon: require('../assets/image/wanjia.png'), really: true },
        { id: 4, position: 0, isMoving: false, eliminated: false, isWinner: false, fieldPosition: 196, key: '4', color: '#ffd166', textColor: '#1a1a2e', icon: require('../assets/image/wanjia.png'), really: true },
        { id: 5, position: 0, isMoving: false, eliminated: false, isWinner: false, fieldPosition: 256, key: '5', color: '#7209b7', textColor: '#fff', icon: require('../assets/image/wanjia.png'), really: true },
        { id: 6, position: 0, isMoving: false, eliminated: false, isWinner: false, fieldPosition: 316, key: '6', color: '#f72585', textColor: '#fff', icon: require('../assets/image/wanjia.png'), really: true },
        { id: 7, position: 0, isMoving: false, eliminated: false, isWinner: false, fieldPosition: 376, key: '7', color: '#4cc9f0', textColor: '#1a1a2e', icon: require('../assets/image/wanjia.png'), really: true },
        { id: 8, position: 0, isMoving: false, eliminated: false, isWinner: false, fieldPosition: 436, key: '8', color: '#4361ee', textColor: '#fff', icon: require('../assets/image/wanjia.png'), really: true }
      ],
      woodenManTimer: null,
      countdownTimer: null,
      showGameResult: false,
      gameResultTitle: '',
      gameResultMessage: '',
      showInstructions: true,
      arr1: [],
      number:'1',
      mutourenyinyue:require('@/assets/sounds/mutourenyinyue.mp3'),
      moleShow:JSON.stringify({marked:'q'}),
      ws2: null,
    }
  },
  created() {

  },
  components: {},
  computed: {
    woodenManClass() {
      return this.woodenManFacing ? 'face-front' : 'face-back';
    },
    activePlayersCount() {
      return this.players.filter(p => !p.eliminated && !p.isWinner).length;
    },
    winnersCount() {
      return this.players.filter(p => p.isWinner).length;
    },
    eliminatedCount() {
      return this.players.filter(p => p.eliminated).length;
    },
    // 为每个玩家计算状态文本和类
    playersWithStatus() {
      return this.players.map(player => {
        let statusText = '等待中';
        let statusClass = '';

        if (player.isWinner) {
          statusText = '获胜者';
          statusClass = 'status-winner';
        } else if (player.eliminated) {
          statusText = '已淘汰';
          statusClass = 'status-eliminated';
        } else if (player.isMoving && !this.woodenManFacing) {
          statusText = '移动中';
          statusClass = 'status-moving';
        } else if (this.woodenManFacing) {
          statusText = '停止中';
          statusClass = 'status-stopped';
        } else {
          statusText = '可以移动';
          statusClass = 'status-moving';
        }

        return {
          ...player,
          statusText,
          statusClass
        };
      });
    }
  },
  watch: {
    // 监听游戏运行状态，自动调整玩家垂直位置以适应游戏区域高度
    gameRunning() {
      this.$nextTick(() => {
        this.adjustPlayerPositions();
      });
    }
  },
  mounted() {
    this.$store.commit('SET_ID','2')
    this.daji1()
    // 初始化时绑定键盘事件
    window.addEventListener('keydown', this.handleKeyDown);
    // 调整玩家位置
    this.adjustPlayerPositions();
    // 监听窗口大小变化
    window.addEventListener('resize', this.adjustPlayerPositions);
      setTimeout(() => {
          console.log('正在重新连接...')
          this.connectWebSocket2()
        }, 3000)
     setTimeout(() => { 
        console.log('一分钟结束游戏')
        // this.ws.send(this.moleShow)
        // 游戏结束
        this.endGame();
    }, 60000)
  },
  beforeUnmount() {
    // 关闭WebSocket连接
    if (this.ws2) {
      this.ws2.close();
      this.ws2 = null;
    }
  },
  methods: {
    daji1(){
       this.$refs.mutourenPlayers.play()
    },
    connectWebSocket2() {
      // 替换为你的 WebSocket 服务地址（需 ws:// 或 wss://）
      //this.ws = new WebSocket('ws://192.168.1.74:8767')
      this.ws2 = new WebSocket('ws://127.0.0.1:8767');
      
      this.ws2.onopen = () => {
        console.log('WebSocket 已连接')
      };
      this.arr1 = JSON.parse(JSON.stringify(this.players));
      this.ws2.onmessage = (event) => {
        // console.log(event)
       // console.log(JSON.parse(event.data))
        const res = JSON.parse(event.data)
        this.differentObjects(res.boxes)
        for (let index = 0; index < res.boxes.length; index++) {
          if(res.boxes[index].is_marked == true){
             if(this.number=='1'){
               this.startGame()
            }
           this.number += 1
          }
        }
        if (res.boxes.length > 0) {
          for (let i = 0; i < this.players.length; i++) {
            for (let j = 0; j < res.boxes.length; j++) {
              if (this.players[i].id == res.boxes[j].track_id) {
                const decodedString = atob(res.boxes[j].head_img.split(',')[1]);
                //将解码后的字符串转换为Uint8Array
                const decodedData = new Uint8Array(decodedString.length);
                for (let z = 0; z < decodedString.length; z++) {
                  decodedData[z] = decodedString.charCodeAt(z);
                }
                // 创建Blob对象
                const blob = new Blob([decodedData], { type: 'image/png' }); // 根据实际情况调整类型，例如'image/jpeg'等
                this.players[i].icon = URL.createObjectURL(blob);
                // 创建可访问的URL
                // this.players[i].really = res.boxes[j].is_marked
                if (res.boxes[j].state == 'moving') {
                  console.log(res.boxes[j].track_id)
                  this.handleKeyDown(res.boxes[j].track_id)
                }
              }
            }
          }
        } 
      };
      this.ws2.onerror = (error) => {
        console.log('连接错误',error)
      };
      this.ws2.onclose = (error) => {
        console.log('连接已关闭',error);
      };
     
    },
    differentObjects(res) {
      const ids1 = this.players.map(item => item.id);
      const ids2 = res.map(item => item.track_id);
      // 找出arr1中有而res中没有的id
      const diffIds1 = ids1.filter(track_id => !ids2.includes(track_id));
      // 找出res中有而arr1中没有的id
      const diffIds2 = ids2.filter(id => !ids1.includes(id));
      // 合并所有不同的id
      const allDiffIds = [...diffIds1, ...diffIds2];
        for(let j = 0; j < this.players.length; j++){
          for(let i = 0; i < allDiffIds.length; i++){
          if(this.players[j].id == allDiffIds[i]){
            this.players[j].really=true
            this.players[j].icon = require('../assets/image/wanjia.png')
          }
        }
      }
     // console.log(allDiffIds); // [2]
    },
    toggleInstructions() {
      this.showInstructions = !this.showInstructions;
    },
    adjustPlayerPositions() {
      // 获取游戏区域高度
      const gameField = document.querySelector('.game-field');
      if (!gameField) return;

      const fieldHeight = gameField.clientHeight;
      const playerCount = this.players.length;
      const spacing = fieldHeight / (playerCount + 1);

      // 更新玩家垂直位置
      this.players.forEach((player, index) => {
        player.fieldPosition = spacing * (index + 1) - 18; // 18px是玩家标记高度的一半
      });
    },
    startGame() {
      if (this.gameRunning) return;

      this.gameRunning = true;
      this.roundCount = 0;
      this.showGameResult = false;

      // 重置玩家状态（除了已经获胜的）
      this.players.forEach(player => {
        if (!player.isWinner) {
          player.position = 0;
          player.eliminated = false;
        }
      });

      // 开始木头人转身循环
      this.startWoodenManCycle();

      // 绑定键盘事件
      window.addEventListener('keydown', this.handleKeyDown);
    },

    startWoodenManCycle() {
      // 清除现有定时器
      if (this.woodenManTimer) clearTimeout(this.woodenManTimer);
      if (this.countdownTimer) clearInterval(this.countdownTimer);

      // 开始新的循环
      this.woodenManFacing = false; // 初始状态为背对
      // 木头人背对人时转头时间10秒随机（8-12秒）
      this.countdown = this.getRandomBackTime();
      this.roundCount++;

      // 开始倒计时
      this.countdownTimer = setInterval(() => {
        this.countdown--;

        if (this.countdown <= 0) {
          // 切换木头人状态
          this.woodenManFacing = !this.woodenManFacing;

          // 根据当前状态设置不同的时间
          if (this.woodenManFacing) {
            // 面对时时间较短（3-5秒）
            this.countdown = this.getRandomFaceTime();
          } else {
            // 背对时时间较长（2-6秒）
            this.countdown = this.getRandomBackTime();
          }

          this.roundCount++;

          // 如果木头人转身面对玩家，检查是否有玩家在移动
          if (this.woodenManFacing) {
            this.checkMovingPlayers();
          }

          // 检查游戏是否结束
          this.checkGameEnd();
        }
      }, 1000);
    },

    getRandomBackTime() {
      // 随机生成2-6秒的时间（木头人背对时间）
      return Math.floor(Math.random() * 5) + 2;
    },

    getRandomFaceTime() {
      // 随机生成3-5秒的时间（木头人面对时间）
      return Math.floor(Math.random() * 3) + 3;
    },

    handleKeyDown(event) {
      if (!this.gameRunning) return;
         console.log(event)
      // 如果木头人面对玩家，任何移动都会导致淘汰
      if (this.woodenManFacing) {
        this.players.forEach(player => {
          if (event == player.key && !player.eliminated && !player.isWinner) {
            // 淘汰该玩家
            player.eliminated = true;
            player.isMoving = false;
          }
        });
        return;
      }

      // 木头人背对玩家，允许移动
      this.players.forEach(player => {
        if (event == player.key && !player.eliminated && !player.isWinner) {
          // console.log('movePlayer', player, event);
          // 移动玩家
          this.movePlayer(player);
        }
      });
    },

    movePlayer(player) {
      if (!this.gameRunning || player.eliminated || player.isWinner) return;

      // 设置玩家为移动状态
      player.isMoving = true;

      // 移动玩家位置 - 改小移动距离（3-6%）
      // const moveAmount = Math.random() * 1 + 3; // 随机移动3-6%
      player.position += 0.3*1;

      // 检查是否到达终点
      if (player.position >= 100) {
        player.position = 100;
        player.isWinner = true;
        player.isMoving = false;

        // 检查游戏是否结束
        this.checkGameEnd();
      }

      // 0.5秒后停止移动状态
      setTimeout(() => {
        player.isMoving = false;
      }, 500);
    },

    checkMovingPlayers() {
      // 检查在木头人面对时是否有玩家在移动
      this.players.forEach(player => {
        if (player.isMoving && !player.eliminated && !player.isWinner) {
          player.eliminated = true;
          player.isMoving = false;
        }
      });
    },

    checkGameEnd() {
      // 检查是否所有玩家都已获胜或被淘汰
      const activePlayers = this.players.filter(p => !p.eliminated && !p.isWinner);

      if (activePlayers.length === 0) {
        // this.ws.send(this.moleShow)
        // 游戏结束
        this.endGame();
        return;
      }

      // 检查是否有玩家获胜
      const winners = this.players.filter(p => p.isWinner);
      if (winners.length > 0) {
        this.endGame();
        // 如果有玩家获胜，可以继续游戏，也可以选择结束
        // 这里我们选择继续，直到所有玩家都结束
      }
    },

    endGame() {
         this.$store.commit('SET_ID', '1')
      this.gameRunning = false;

      // 清除定时器
      if (this.woodenManTimer) clearTimeout(this.woodenManTimer);
      if (this.countdownTimer) clearInterval(this.countdownTimer);

      // 移除键盘事件监听
      window.removeEventListener('keydown', this.handleKeyDown);

      // 显示游戏结果
      const winners = this.players.filter(p => p.isWinner);

      if (winners.length > 0) {
        this.gameResultTitle = '游戏结束！';
        if (winners.length === 1) {
          this.gameResultMessage = `玩家 ${winners[0].id} 获胜！`;
        } else {
          const winnerIds = winners.map(w => w.id).join(', ');
          this.gameResultMessage = `玩家 ${winnerIds} 获胜！`;
        }
      } else {
        this.gameResultTitle = '游戏结束！';
        this.gameResultMessage = '所有玩家都被淘汰了！';
      }

      this.showGameResult = true;
      setTimeout(() => {
        this.showGameResult = false;
        this.$store.commit('SET_YUNDONGTYPE', '')
        this.$router.push({ path: '/'});
      }, 5000);
    },

    closeResult() {
      this.showGameResult = false;
    },

    resetGame() {
      // 清除定时器
      if (this.woodenManTimer) clearTimeout(this.woodenManTimer);
      if (this.countdownTimer) clearInterval(this.countdownTimer);

      // 移除键盘事件监听
      window.removeEventListener('keydown', this.handleKeyDown);

      // 重置所有数据
      this.gameRunning = false;
      this.woodenManFacing = false;
      this.countdown = 0;
      this.roundCount = 0;
      this.showGameResult = false;

      // 重置玩家状态
      this.players.forEach(player => {
        player.position = 0;
        player.isMoving = false;
        player.eliminated = false;
        player.isWinner = false;
      });
    }
  },
  beforeDestroy() {
    // 清除定时器和事件监听
    if (this.woodenManTimer) clearTimeout(this.woodenManTimer);
    if (this.countdownTimer) clearInterval(this.countdownTimer);
    window.removeEventListener('keydown', this.handleKeyDown);
    window.removeEventListener('resize', this.adjustPlayerPositions);
  }
}
</script>

<style>
#appShow2 {
  width: 100vw;
  height: 100vh;
  display: flex;
  flex-direction: column;
  overflow: hidden;
  position: relative;
}

.game-background2 {
  position: absolute;
  width: 100%;
  height: 100%;
  z-index: -1;
  /* max-width: 1200px; */
  /* margin: 0 auto 30px;
  min-height: 800px; */
}

.background-image {
  width: 100%;
  height: 100%;
  display: block;
}

header {
  text-align: center;
  margin-bottom: 15px;
  padding-bottom: 10px;
  border-bottom: 2px solid rgba(255, 255, 255, 0.1);
  flex-shrink: 0;
}

h1 {
  font-size: 2.2rem;
  color: #ffd166;
  text-shadow: 0 0 10px rgba(255, 209, 102, 0.5);
  margin-bottom: 5px;
}

.game-area {
  display: flex;
  flex-direction: column;
  flex: 1;
  overflow: hidden;
}

.game-main {
  display: flex;
  flex: 1;
  gap: 15px;
  overflow: hidden;
  margin-bottom: 10px;
}

.left-panel {
  width: 300px;
  height: 300px;
