<template>
  <div class="mian" ref="plane">
    <div class="point current" :style="pointStyle">
        </div>
  </div>
</template>

<script>
export default {
  data() {
    return {
      planeWidth: 0,
        planeHeight: 0,
        currentPoint: { x: 0, y: 0 },
    };
  },
  async mounted() {
    this.initGrid()
  },
  beforeDestroy() {
   
  },
  methods: {
        generateRandomPoint() {
          // 确保点在平面内（减去点的半径20px）
          const maxX = this.planeWidth - 40;
          const maxY = this.planeHeight - 40;
          
          return {
            x: Math.floor(Math.random() * maxX) + 20,
            y: Math.floor(Math.random() * maxY) + 20
          };
        },
        generatePoint() {
          const newPoint = this.generateRandomPoint();
          if (!newPoint) return;   
          // 更新当前点
          this.currentPoint = newPoint;
          console.log(this.currentPoint);
        },
    initGrid() {
          const plane = this.$refs.plane;
          if (plane) {
            this.planeWidth = plane.clientWidth;
            this.planeHeight = plane.clientHeight;
            
            // 初始点放在中心
            this.currentPoint = {
              x: this.planeWidth / 2,
              y: this.planeHeight / 2
            };
          }
          setInterval(() => {
              this.generatePoint();
            }, 1000);
        }
  },
  computed: {
        pointStyle() {
          return {
            left: this.currentPoint.x + 'px',
            top: this.currentPoint.y + 'px',
            transition: 'left 1s ease, top 1s ease'
          };
        },
        
      },
};
</script>

<style scoped>
.mian{
  width: 1920px;
  height: 1080px;
}
   .point {
      position: absolute;
      width: 40px;
      height: 40px;
      border-radius: 50%;
      background: linear-gradient(135deg, #ff7e5f, #feb47b);
      box-shadow: 0 0 15px rgba(255, 126, 95, 0.7);
      cursor: pointer;
      display: flex;
      justify-content: center;
      align-items: center;
      font-weight: bold;
      color: #fff;
      text-shadow: 0 1px 2px rgba(0,0,0,0.5);
      transition: transform 0.3s, box-shadow 0.3s;
      transform: translate(-50%, -50%);
      z-index: 10;
    }
     .current {
      background: linear-gradient(135deg, #ff7e5f, #feb47b);
    }
</style>