import Vue from 'vue'
import App from './App.vue'
import ElementUI from 'element-ui';             //全局引入element
import 'element-ui/lib/theme-chalk/index.css';    //全局引入element的样式
// collapse 展开折叠
import CollapseTransition from 'element-ui/lib/transitions/collapse-transition';
Vue.component(CollapseTransition.name, CollapseTransition)
import { setCookie, getCookie, delCookie } from "./utils/util";
// 将自动注册所有组件为全局组件
import dataV from '@jiaminghi/data-view'
Vue.use(dataV)
import scroll from 'vue-seamless-scroll'
Vue.use(scroll)
// 引入echarts
//全局引入echarts
import * as echarts from 'echarts';
//需要挂载到Vue原型上
Vue.prototype.$echarts = echarts;
// 高德地图echarts依赖
require('./config/echarts-amap.min.js')
// require("echarts/dist/extension/dataTool.js");
require('./config/china.js')
require('./config/world.js')
require('./config/simplex.js')
import router from './router'
// 引入公共样式
import './assets/css/index.css'
// 引入状态管理
import store from './vuex/store';
import axios from 'axios';
Vue.prototype.$axios = axios;
Vue.prototype.$http = axios
// 引入音频

Vue.prototype.TEST_URL = "http://192.168.1.119:7000/"; //  线下
//Vue.prototype.TEST_URL = "http://101.132.97.14:8541/"; //  线上
Vue.config.productionTip = false
axios.interceptors.request.use(config => {
  // 检查是否存在认证token，如果存在则添加到请求头中
  const token =getCookie("Authorization") // 假设你的token存储在sessionStorage中
   //console.log(token,'3333333333')
  if (token) {
    config.headers.Authorization = `${token}`;
  }
  return config;
}, error => {
  return Promise.reject(error);
})
Vue.use(ElementUI);     //全局注入element
new Vue({
  router,
  store,
  render: h => h(App)
}).$mount('#app')
