import Vue from 'vue'
import Vuex from 'vuex'

Vue.use(Vuex)

export default new Vuex.Store({
  state: {
    currentIndex: 1,
    count: 0,
    countOne:0,
    countTwo:0,
    yundongType: '',
    id:'0',
    scriptName:'',
    base64Image:'',
  },
  mutations: {
    UPDATE_INDEX(state, index) {
      state.currentIndex = index
    },
    UPDATE_MESSAGE(state, count) {
      // 确保传入的 count 是数字类型
      state.count = typeof count === 'number' ? count : parseInt(count) || 0
    },
    UPDATE_MESSAGE_ONE(state, count) {
      // 确保传入的 count 是数字类型
      state.countOne = typeof count === 'number' ? count : parseInt(count) || 0
    },
    UPDATE_MESSAGE_TWO(state, count) {
      // 确保传入的 count 是数字类型
      state.countTwo = typeof count === 'number' ? count : parseInt(count) || 0
    },
    SET_YUNDONGTYPE(state, items) {
      state.yundongType = items
    },
    SET_ID(state, items) {
      state.id = items
    },
    SET_SCRIPTNAME(state, items) {
      state.scriptName = items
    },
    SET_BASE64IMAGE(state, items) {
      state.base64Image = items
    }
  },
  actions: {
  },
  modules: {
  },
  getters: {
    getMessage: state => state.count
  }
})