import Vue from 'vue'
import VueRouter from 'vue-router'
import Login from '../views/Login.vue'
import equipment from '@/views/equipment'//设备设置
import ChemicalReagents from '@/views/ChemicalReagents'//化学试剂
import fixedAssets from '@/views/fixedAssets.vue'
import threshold from '@/views/threshold.vue'
import monitoring from '@/views/monitoring.vue'
import HistoricalAlarm from '@/views/HistoricalAlarm.vue'
Vue.use(VueRouter)

const routes = [
	{
		path: '/Login',
		name: 'Login',
		component: Login
	},
	{
		path: '/SacleBox',
		name: 'SacleBox',
		component: () => import(/* webpackChunkName: "about" */ '../components/SacleBox.vue')
	},
	{
		path: '/boxyemian',
		name: 'boxyemian',
		component: () => import(/* webpackChunkName: "about" */ '../components/boxyemian.vue')
	},
	{
		//化学试剂
		path: '/ChemicalReagents',
		name: 'ChemicalReagents',
		component: ChemicalReagents,
	},
	{
		//设备设置
		path: '/equipment',
		name: 'equipment',
		component: equipment,
	},
	{
		//设备设置
		path: '/fixedAssets',
		name: 'fixedAssets',
		component: fixedAssets,
	},
	{
		//设备设置
		path: '/threshold',
		name: 'threshold',
		component: threshold,
	},
	{
		//初始
		path: '/',
		name: 'monitoring',
		component: monitoring,
	},
	{
		//初始
		path: '/HistoricalAlarm',
		name: 'HistoricalAlarm',
		component: HistoricalAlarm,
	},
]

const router = new VueRouter({
	mode: 'history',
	base: process.env.BASE_URL,
	routes
})

export default router
