<template>
  <div id="appShow">
    <div class="timeData">{{ timeLeft }}</div>
    <div class="totalScore">{{ score }}</div>
    <!-- 添加游戏背景图片 -->
    <div class="game-background">
      <img src="../assets/image/beijingtu.png" alt="游戏背景" class="background-image">

      <!-- 将地鼠洞定位到背景图片的相应位置 -->
      <div class="game-board">
        <div v-for="(hole, index) in holes" :key="index">
          <div class="hole" @click="hitMole(index)" v-show="hole.show" :style="getHoleStyle(index)">
            <div class="mole" :class="{ active: hole.active }">
              <img :src="moleImages[hole.type]" style="width: 100%;height: 100%;" alt="" />
            </div>
          </div>
          <div class="hole-border" :style="getHoleStyles(index)" v-show="hole.reayllShow">
            <img src="../assets/image/really.png" class="reallyImg" alt="">
          </div>
        </div>
      </div>
    </div>

    <!-- <div class="game-info game-board">
      <div v-for="(hole, index) in holes" :key="index"> {{ hole.id + 1 }} 号得分: <span
          style="font-weight: 800;font-size: 2rem;">{{ hole.num }}</span></div>
    </div> -->

    <!-- <div class="controls">
      <button @click="startGame" :disabled="gameRunning">开始游戏</button>
      <button @click="resetGame">重置游戏</button>
    </div> -->
    <!-- <div v-if="gameOver" class="game-over">
      游戏结束！
    </div> -->
    <div class="instructions">
      <p>点击出现的地鼠来得分！游戏时间: 60秒</p>
    </div>

    <audio ref="audioPlayer" :src="audioSrc"></audio>
    <div @click="daji">
       <audio ref="audioPlayers" :src="beijingyinyue" loop></audio> 
    </div>
    <div @click="dazhong">
          <audio ref="audioPlayers1" :src="dazhongshengyin"></audio>
    </div>
    
    <div ref="myElement" class="dongzuo">
      <img src="../assets/image/fEujEcQ8y.jpg" class="paihangbangImg" alt="">
      <div class="chengji">
        <div class="C-consert" v-for="(hole, index) in holest" :key="index">
          <div class="binghao">{{ hole.id + 1 }} 洞</div>
          <div class="C-chengji">{{ hole.num }}</div>
        </div>
      </div>
    </div>
    <div class="mole-types">
      <div class="mole-type">
        <div class="mole-preview normal">
          <img :src="moleImages.normal" style="width: 100%;height: 100%;display: block;" alt="普通鼠">
        </div>
        <div>普通鼠: <strong>1分</strong></div>
      </div>
      <div class="mole-type">
        <div class="mole-preview advanced">
          <img :src="moleImages.advanced" style="width: 100%;height: 100%;display: block;" alt="高级鼠">
        </div>
        <div>高级鼠: <strong>2分</strong></div>
      </div>
      <div class="mole-type">
        <div class="mole-preview rare">
          <img :src="moleImages.rare" style="width: 100%;height: 100%;display: block;" alt="稀有鼠">
        </div>
        <div>稀有鼠: <strong>3分</strong></div>
      </div>
    </div>
    <div class="FinalScore" v-show="FinalScoreShow">
      <!-- <div class=""></div> -->
    </div>
  </div>
</template>
<script>
export default {
  name: 'App',
  data() {
    return {
      moleImages: {
        normal: require('../assets/image/6164202_752_30.png'),// 老鼠表情符号
        advanced: require('../assets/image/6164629_754_30.png'), // 老鼠表情符号变体
        rare: require('../assets/image/6165002_756_30.png'), // 老鼠+火表情符号
      },
      holes: [
        {
          id: 0,
          active: false,
          type: 'normal',
          show: false,
          num: 0,
          reayllShow: true
        },
        {
          id: 1,
          active: false,
          type: 'normal',
          show: false,
          num: 0,
          reayllShow: true
        },
        {
          id: 2,
          active: false,
          type: 'normal',
          show: false,
          num: 0,
          reayllShow: true
        }, {
          id: 3,
          active: false,
          type: 'normal',
          show: false,
          num: 0,
          reayllShow: true
        },
        {
          id: 4,
          active: false,
          type: 'normal',
          show: false,
          num: 0,
          reayllShow: true
        },
      ],
      holest: [
        {
          id: 0,
          active: false,
          show: true,
          num: 0
        },
        {
          id: 1,
          active: false,
          show: true,
          num: 0
        },
        {
          id: 2,
          active: false,
          show: true,
          num: 0
        }, {
          id: 3,
          active: false,
          show: true,
          num: 0
        },
        {
          id: 4,
          active: false,
          show: true,
          num: 0
        },
      ],
      // 洞口在背景图片上的定位坐标 (相对于背景图片的百分比)
      holePositions: [
        { left: '26.3%', top: '38%' },   // 洞1
        { left: '59.5%', top: '38%' },   // 洞2
        { left: '9%', top: '65%' },   // 洞3
        { left: '42.8%', top: '65%' },   // 洞4
        { left: '77.6%', top: '65%' },   // 洞5
      ],
      holePositiones: [
        { left: '29%', top: '48.5%' },   // 洞1
        { left: '62.5%', top: '48.5%' },   // 洞2
        { left: '12%', top: '76%' },   // 洞3
        { left: '45.8%', top: '76%' },   // 洞4
        { left: '80.8%', top: '76%' },   // 洞5
      ],
      score: 0,
      timeLeft: 60,
      gameRunning: false,
      gameOver: false,
      gameInterval: null,
      moleInterval: null,
      audioSrc: require('@/assets/sounds/miss.mp3'),
      beijingyinyue: require('@/assets/sounds/637b432e724e4176.mp3'),
      dazhongshengyin: require('../assets/sounds/63770389270e8217.mp3'),
      FinalScoreShow: false,//显示分数
      number: 1,
      moleShow:JSON.stringify({marked:'q'}),
      element: null,
      ws1: null,
    }
  },
  mounted() {
    this.$store.commit('SET_ID','2')
    this.daji()
      setTimeout(() => {
          console.log('正在重新连接...')
          this.connectWebSocket1()
        }, 3000)
    this.preloadImages()
  },
  beforeUnmount() {
    // 关闭WebSocket连接
    if (this.ws1) {
      this.ws1.close();
      this.ws1 = null;
    }
},
  methods: {
    daji(){
        this.$refs.audioPlayers.play()
    },

    // 获取洞口定位样式
    getHoleStyle(index) {
      if (this.holePositions[index]) {
        return {
          position: 'absolute',
          left: this.holePositions[index].left,
          top: this.holePositions[index].top,
          width: '280px',
          height: '280px',
          zIndex: 2,
          // 预加载图片
          imagesLoaded: false
        };
      }
      return {};
    },
    getHoleStyles(index) {
      if (this.holePositiones[index]) {
        return {
          position: 'absolute',
          left: this.holePositiones[index].left,
          top: this.holePositiones[index].top,
          zIndex: 1,
          // 预加载图片
          imagesLoaded: false
        };
      }

    },
    startGame() {
      
      // 重置游戏状态
      this.score = 0;
      this.timeLeft = 60;
      this.gameOver = false;
      this.gameRunning = true;
      // this.holes = [
      //   {
      //     id: 0,
      //     active: false,
      //     type: 'normal',
      //     show: false,
      //     num: 0,
      //     reayllShow: true
      //   },
      //   {
      //     id: 1,
      //     active: false,
      //     type: 'normal',
      //     show: false,
      //     num: 0,
      //     reayllShow: true
      //   },
      //   {
      //     id: 2,
      //     active: false,
      //     type: 'normal',
      //     show: false,
      //     num: 0,
      //     reayllShow: true
      //   }, {
      //     id: 3,
      //     active: false,
      //     type: 'normal',
      //     show: false,
      //     num: 0,
      //     reayllShow: true
      //   },
      //   {
      //     id: 4,
      //     active: false,
      //     type: 'normal',
      //     show: false,
      //     num: 0,
      //     reayllShow: true
      //   },
      // ],
      // this.holest = [
      //     {
      //       id: 0,
      //       active: false,
      //       show: true,
      //       num: 0
      //     },
      //     {
      //       id: 1,
      //       active: false,
      //       show: true,
      //       num: 0
      //     },
      //     {
      //       id: 2,
      //       active: false,
      //       show: true,
      //       num: 0
      //     }, {
      //       id: 3,
      //       active: false,
      //       show: true,
      //       num: 0
      //     },
      //     {
      //       id: 4,
      //       active: false,
      //       show: true,
      //       num: 0
      //     },
      //   ],
        // 隐藏所有地鼠
        this.holes.forEach(hole => {
          hole.active = false;
        });

      // 开始游戏计时
      this.gameInterval = setInterval(() => {
        this.timeLeft--;

        if (this.timeLeft <= 0) {
           this.$store.commit('SET_ID', 1)
          console.log('结束游戏',this.moleShow)
          this.FinalScoreShow = true
          this.element = this.$refs.myElement;
          this.element.style.top = '50%'
          this.element.style.left = '50%'
          this.element.style.transform = 'translate(-50%,-50%)'
          this.endGame();
          setTimeout(() => {
            this.score=0
            this.number=1
            this.FinalScoreShow = false
            this.element.style.top = '15%'
            this.element.style.left = '2%'
            this.element.style.transform = 'translate(0%,0%)'
            this.holes = [
              {
                id: 0,
                active: false,
                type: 'normal',
                show: false,
                num: 0,
                reayllShow: true
              },
              {
                id: 1,
                active: false,
                type: 'normal',
                show: false,
                num: 0,
                reayllShow: true
              },
              {
                id: 2,
                active: false,
                type: 'normal',
                show: false,
                num: 0,
                reayllShow: true
              }, {
                id: 3,
                active: false,
                type: 'normal',
                show: false,
                num: 0,
                reayllShow: true
              },
              {
                id: 4,
                active: false,
                type: 'normal',
                show: false,
                num: 0,
                reayllShow: true
              },
            ]
            this.holest = [
              {
                id: 0,
                num: 0
              },
              {
                id: 1,
                num: 0
              },
              {
                id: 2,
                num: 0
              }, {
                id: 3,
                num: 0
              },
              {
                id: 4,
                num: 0
              },
            ]
            console.log('this.holes')
            this.$store.commit('SET_YUNDONGTYPE', '')
            this.$router.push({ path: '/'});
          }, 5000);
        }
      }, 1000);

      // 开始地鼠出现
      this.moleInterval = setInterval(() => {
        this.showRandomMole();
      }, 2500);
    },
    connectWebSocket1() {
      // 替换为你的 WebSocket 服务地址（需 ws:// 或 wss://）
      //this.ws = new WebSocket('ws://192.168.1.74:8766')
      this.ws1 = new WebSocket('ws://127.0.0.1:8766');
      this.ws1.onopen = () => {
        console.log('WebSocket 已连接打地鼠')
      };

      this.ws1.onmessage = (event) => {
        if (this.number == '1') {
          this.holes= [
        {
          id: 0,
          active: false,
          type: 'normal',
          show: false,
          num: 0,
          reayllShow: true
        },
        {
          id: 1,
          active: false,
          type: 'normal',
          show: false,
          num: 0,
          reayllShow: true
        },
        {
          id: 2,
          active: false,
          type: 'normal',
          show: false,
          num: 0,
          reayllShow: true
        }, {
          id: 3,
          active: false,
          type: 'normal',
          show: false,
          num: 0,
          reayllShow: true
        },
        {
          id: 4,
          active: false,
          type: 'normal',
          show: false,
          num: 0,
          reayllShow: true
        },
      ]
        }
        // console.log(event)
        // console.log(JSON.parse(event.data))
        const res = JSON.parse(event.data)
        for (let i = 0; i < res.boxes.length; i++) {
          if (res.boxes[i].is_marked == true) {
            console.log(JSON.parse(event.data),'3432423343')
            if(this.number=='1'){
               this.startGame()
            }
           this.number += 1
          }
          // console.log(res.boxes[i].id,'45345345435435453')
          if (res.boxes[i].count_event == true) {
            //console.log(JSON.parse(event.data))
          console.log(res.boxes[i].id, '45345345435435453')

            let currentIndex = res.boxes[i].id
            this.holes[currentIndex].active = true;
            this.hitMole(currentIndex)
          }
          if (res.boxes[i].in_if == true) {
           console.log(JSON.parse(event.data))
            let currentIndex = res.boxes[i].id
            this.holes[currentIndex].reayllShow = false;
            this.holes[currentIndex].show = true;
             console.log(this.holes)
          }
          if (res.boxes[i].in_if == false) {
           // console.log(JSON.parse(event.data))
            let currentIndex = res.boxes[i].id
            this.holes[currentIndex].reayllShow = true;
          }
        }
       
        // const currentIndex = res.current_value
        // this.$store.commit('UPDATE_INDEX', currentIndex)
      };

      this.ws1.onerror = (error) => {
        console.log('连接错误',error)
      };
      this.ws1.onclose = (error) => {
        console.log('连接已关闭',error);
      };
        // setTimeout(() => {
        //   console.log('正在重新连接...')
        //   this.connectWebSocket1()
        // }, 3000)
    },
    showRandomMole() {
      var arr = []
      // 隐藏所有地鼠
      this.holes.forEach(hole => {
        hole.active = false;
        if (hole.show == true) {
          arr.push(hole)
        }
      });
      //console.log(arr, '434343243423')
      // 随机选择一个洞显示地鼠
      const randomIndex = Math.floor(Math.random() * arr.length);
      console.log(randomIndex);
      const Idindex = arr[randomIndex].id
      // console.log(Idindex, '434343243423')
      const randomType = this.getRandomMoleType();
      //console.log(randomType, '6666666666')
      this.holes[Idindex].type = randomType.type;
      this.holes[Idindex].active = true;

      //console.log(this.holes, '434343243423')

      // 设置地鼠自动消失
      setTimeout(() => {
        this.holes[Idindex].active = false;
      }, 2000);
    },
    getRandomMoleType() {
      // 根据概率随机选择老鼠类型
      // 普通鼠: 60%, 高级鼠: 30%, 稀有鼠: 10%
      const random = Math.random().toFixed(2);
      //console.log(random, '434343243423')
      if (random < 0.5) {
        return { type: 'normal', score: 1, disappearTime: 1000 };
      } else if (random < 0.9) {
        return { type: 'advanced', score: 2, disappearTime: 800 };
      } else {
        return { type: 'rare', score: 3, disappearTime: 600 };
      }
    },
    dazhong(){
         this.$refs.audioPlayers1.play()
    },
    hitMole(index) {
      //this.$refs.audioPlayer.play()
      console.log('点击了洞', index);
      if (this.holes[index].active) {
        this.dazhong()
        // 击中地鼠，增加分数
        if (this.holes[index].type === 'normal') {
          this.holes[index].num += 1;
        } else if (this.holes[index].type === 'advanced') {
          this.holes[index].num += 2;
        } else if (this.holes[index].type === 'rare') {
          this.holes[index].num += 3;
        }
        var sum = 0
        for (let i = 0; i < this.holes.length; i++) {
          sum += this.holes[i].num;
        }
        this.score = sum
        // 立即隐藏地鼠
        this.holes[index].active = false;
      }
      console.log(this.holes, '222222222')
      this.holest = [...this.holes].sort((a, b) => b.num - a.num)
      // console.log(this.holest, '555')
    },

    endGame() {
       
      this.timeLeft = 60;
      this.gameRunning = false;
      this.gameOver = true;
      clearInterval(this.gameInterval);
      clearInterval(this.moleInterval);
      
      // 隐藏所有地鼠

    },
    resetGame() {
      this.gameRunning = false;
      clearInterval(this.gameInterval);
      clearInterval(this.moleInterval);

      this.holes= [
        {
          id: 0,
          active: false,
          type: 'normal',
          show: false,
          num: 0,
          reayllShow: true
        },
        {
          id: 1,
          active: false,
          type: 'normal',
          show: false,
          num: 0,
          reayllShow: true
        },
        {
          id: 2,
          active: false,
          type: 'normal',
          show: false,
          num: 0,
          reayllShow: true
        }, {
          id: 3,
          active: false,
          type: 'normal',
          show: false,
          num: 0,
          reayllShow: true
        },
        {
          id: 4,
          active: false,
          type: 'normal',
          show: false,
          num: 0,
          reayllShow: true
        },
      ],
      this.holest = [
        {
          id: 0,
          active: false,
          show: true,
          num: 0
        },
        {
          id: 1,
          active: false,
          show: true,
          num: 0
        },
        {
          id: 2,
          active: false,
          show: true,
          num: 0
        }, {
          id: 3,
          active: false,
          show: true,
          num: 0
        },
        {
          id: 4,
          active: false,
          show: true,
          num: 0
        },
      ],
        this.score = 0;
      this.timeLeft = 60;
      this.gameOver = false;
    },
    // 预加载图片
    preloadImages() {
      const imageUrls = Object.values(this.moleImages);
      let loadedCount = 0;

      imageUrls.forEach(url => {
        const img = new Image();
        img.src = url;
        img.onload = () => {
          loadedCount++;
          if (loadedCount === imageUrls.length) {
            this.imagesLoaded = true;
            console.log('所有图片已加载完成');
          }
        };
        img.onerror = () => {
          // 如果主图片加载失败，尝试使用备用图片
          console.log('图片加载失败，尝试备用图片');
          this.useBackupImages();
        };
      });
    },

    useBackupImages() {
      this.moleImages = { ...this.backupImages };
    }
  },
  beforeDestroy() {
    // 清理定时器
    if (this.gameInterval) clearInterval(this.gameInterval);
    if (this.moleInterval) clearInterval(this.moleInterval);
  }
}
</script>
<style>
#appShow {
  /* background-color: rgba(255, 255, 255, 0.9);
  border-radius: 20px;
  box-shadow: 0 10px 30px rgba(0, 0, 0, 0.2);
  padding: 30px; */
  /* max-width: 1876px; */
  width: 100%;
  height: 100vh;
  text-align: center;
  /* margin: 10vh auto; */

}

/* 游戏背景容器 */
.game-background {
  position: relative;
  width: 100%;
  height: 100%;
  /* max-width: 1200px; */
  /* margin: 0 auto 30px;
  min-height: 800px; */
}

/* 背景图片 */
.background-image {
  width: 100%;
  height: 100%;
  display: block;
}

/* 游戏板定位 */
.game-board {
  position: absolute;
  top: 0;
  left: 0;
  width: 100%;
  height: 100%;
  display: block;
}

.hole-border {
  width: 180px;
  height: 90px;
}

.reallyImg {
  width: 100%;
  height: 100%;
  animation: pulse 1.5s infinite;
}

@keyframes pulse {
  0% {
    transform: scale(1);
  }

  50% {
    transform: scale(1.1);
  }

  100% {
    transform: scale(1);
  }
}

.timeData {
  width: 90px;
  height: 90px;
  /* background-color: #27ae60; */
  border-radius: 50%;
  position: absolute;
  top: 0vh;
  right: 35px;
  line-height: 14.5vh;
  text-align: center;
  z-index: 10;
  font-size: 7vh;
  color: #0b6ad6;
  font-weight: 550
}

h1 {
  color: #2c3e50;
  margin-bottom: 20px;
  font-size: 2.5rem;
  text-shadow: 2px 2px 4px rgba(0, 0, 0, 0.1);
}

.game-info {
  display: flex;
  justify-content: space-between;
  background-color: #34495e;
  color: white;
  padding: 15px;
  border-radius: 10px;
  margin-bottom: 20px;
  font-size: 1.5rem;
  display: none;
}

/* 洞口样式 */
.hole {
  position: absolute;
  width: 120px;
  height: 120px;
  background-color: transparent;
  border-radius: 50%;
  overflow: hidden;
  cursor: pointer;
  transition: transform 0.1s;
  z-index: 2;
  /* border: 1px solid #27ae60; */
}

.hole:active {
  transform: scale(0.95);
}

.mole {
  position: absolute;
  width: 100%;
  height: 100%;
  background-color: transparent;
  border-radius: 50%;
  bottom: -100%;
  left: 0;
  transition: bottom 0.3s;
  z-index: 1;
}

.mole.active {
  bottom: 0;
}

.controls {
  position: fixed;
  bottom: -10px;
  left: 50%;
  transform: translateX(-50%);
}

button {
  background-color: #2ecc71;
  color: white;
  border: none;
  padding: 12px 25px;
  font-size: 1.1rem;
  border-radius: 50px;
  cursor: pointer;
  transition: all 0.3s;
  box-shadow: 0 4px 0 #27ae60;
  margin: 0 10px;
}

button:hover {
  background-color: #27ae60;
  transform: translateY(2px);
